// resample_audio.c - تغيير sample rate أو channel layout باستخدام libswresample
#include <libswresample/swresample.h>
#include <stdio.h>

int main(void) {
    SwrContext *swr = swr_alloc();
    int64_t src_ch_layout = AV_CH_LAYOUT_STEREO;
    int64_t dst_ch_layout = AV_CH_LAYOUT_MONO;
    int src_rate = 44100;
    int dst_rate = 22050;
    enum AVSampleFormat src_fmt = AV_SAMPLE_FMT_FLT;
    enum AVSampleFormat dst_fmt = AV_SAMPLE_FMT_S16;

    av_opt_set_int(swr, "in_channel_layout", src_ch_layout, 0);
    av_opt_set_int(swr, "out_channel_layout", dst_ch_layout, 0);
    av_opt_set_int(swr, "in_sample_rate", src_rate, 0);
    av_opt_set_int(swr, "out_sample_rate", dst_rate, 0);
    av_opt_set_sample_fmt(swr, "in_sample_fmt", src_fmt, 0);
    av_opt_set_sample_fmt(swr, "out_sample_fmt", dst_fmt, 0);
    swr_init(swr);

    // التحويل: 44100Hz stereo -> 22050Hz mono
    uint8_t *src_buf[2] = {0};
    uint8_t *dst_buf[1] = {0};
    int src_nb_samples = 1024;
    int src_linesize = src_nb_samples * av_get_bytes_per_sample(src_fmt) * 2; // stereo
    int dst_linesize = src_nb_samples * av_get_bytes_per_sample(dst_fmt);     // mono

    // av_samples_alloc_and_fill يُملأ buffer بالقيمة الصامتية
    av_samples_alloc_and_fill(src_buf, src_linesize, src_fmt, 0.0f);
    av_samples_alloc_and_fill(dst_buf, dst_linesize, dst_fmt, 0.0f);

    // التحويل الفعلي
    int dst_nb_samples = swr_convert(swr, dst_buf, dst_linesize,
        src_buf, src_linesize, src_nb_samples);
    printf("تحويل: %d -> %d عينة
", src_nb_samples, dst_nb_samples);

    av_freep(&src_buf[0]);
    av_freep(&dst_buf[0]);
    swr_free(&swr);
    return 0;
}
